To proxy requests in an ASP.NET Core API, you can use the `HttpClient` class to send the request to the target endpoint and then return the response to the client. Here's a basic example:

**ProxyController.cs**
```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet("{url}")]
    public async Task<IActionResult> ProxyRequestAsync(string url)
    {
        var request = new HttpRequestMessage(HttpMethod.Get, url);
        var client = _httpClientFactory.CreateClient();
        var response = await client.SendAsync(request);

        if (response.IsSuccessStatusCode)
        {
            return new OkObjectResult(await response.Content.ReadAsStringAsync());
        }
        else
        {
            return new StatusCodeResult((int)response.StatusCode);
        }
    }
}
```
