// Custom hook file: useNotification.context.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from '../helpers/notification.helpers';

interface NotificationContextProps {
  children: React.ReactNode;
}

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [notificationElement, setNotificationElement] = useState<HTMLHuelNotificationElement | null>(notificationElem);

  useEffect(() => {
    setNotificationElement(notificationElem);
  }, [notificationElem]);

  const notify = async (props: NotificationProps) => {
    if (!notificationElement) return;

    const { heading, subheading, type } = props;
    try {
      await notificationElement.open({
        heading,
        subheading,
        type,
      });
    } catch (error) {
      console.error(error);
    }
  };

  return { notify };
};

export { NotificationContext, useNotification };
